// // This module implements a D flip-flop with enable and reset capabilities.
// Inputs: D (data input), C (clock input), E (enable input), R (reset input)
// Outputs: Q (output)

// Behavior:
// - On rising edge of C, Q reflects D if E is asserted; otherwise, it holds its previous value.
// - On assertion of R, Q is set to 0 regardless of D or E.

module dff_en_rst (
    input D, C, E, R,
    output Q
);

reg Q_reg;

always @(posedge C) begin
    if (R == 1) begin // Inverted reset condition
        Q_reg <= 1; // Inverted reset value
    end else if (E == 0) begin // Inverted enable condition
        Q_reg <= ~D; // Inverted logic for D
    end
end

assign Q = ~Q_reg; // Inverted output assignment

endmodule
module dff_en_rst (
    input D, C, E, R,
    output Q
);

reg Q_reg;

always @(posedge C) begin
    if (R == 0) begin
        Q_reg <= 0;
    end else if (E == 1) begin
        Q_reg <= D;
    end
end

assign Q = Q_reg;

endmodule

